-- ============================================
-- MIGRATION: Add bot_config table
-- Run this on existing databases to add the config table
-- without dropping/recreating all other tables.
-- Usage: psql -h localhost -U n8n -d n8n -f scripts/migrate-add-bot-config.sql
-- ============================================

CREATE TABLE IF NOT EXISTS bot_config (
    id SERIAL PRIMARY KEY,
    category VARCHAR(50) NOT NULL,
    key VARCHAR(100) NOT NULL,
    value TEXT NOT NULL,
    value_type VARCHAR(20) DEFAULT 'number',
    label VARCHAR(200),
    description TEXT,
    min_value TEXT,
    max_value TEXT,
    updated_at TIMESTAMP DEFAULT NOW(),
    UNIQUE(category, key)
);

-- Upsert all config values (won't overwrite existing user changes)
ON CONFLICT (category, key) DO NOTHING;

SELECT 'Migration complete: bot_config table created with ' || COUNT(*) || ' entries' AS result FROM bot_config;
